console.log('let ilə dəyişən nümunəsi...');
let personName = 'Ayxan';
console.log('Ad:', personName);
// Output:
// let ilə dəyişən nümunəsi...
// Ad: Ayxan

console.log('Yenidən təyin nümunəsi...');
let count = 10;
count = 20; // Yenidən təyin
console.log('Dəyər:', count);
// Output:
// Yenidən təyin nümunəsi...
// Dəyər: 20

console.log('Yenidən elan nümunəsi...');
let number = 5;
// let number = 15; // Səhv: Identifier 'number' has already been declared
console.log('Dəyər:', number);
// Output:
// Yenidən elan nümunəsi...
// Dəyər: 5

console.log('Blok scope nümunəsi...');
if (true) {
    let message = 'Blok daxilində';
    console.log('Blok daxilində:', message);
}
// console.log('Blok xaricində:', message); // Səhv: message is not defined
// Output:
// Blok scope nümunəsi...
// Blok daxilində: Blok daxilində

console.log('Hoisting nümunəsi...');
// console.log(value); // Səhv: Cannot access 'value' before initialization
let value = 100;
console.log('Təyin olunduqdan sonra:', value);
// Output:
// Hoisting nümunəsi...
// Təyin olunduqdan sonra: 100

console.log('let vs var nümunəsi...');
if (true) {
    var varValue = 'Var dəyəri';
    let letValue = 'Let dəyəri';
}
console.log(varValue); // İşləyir
// console.log(letValue); // Səhv: letValue is not defined
// Output:
// let vs var nümunəsi...
// Var dəyəri

console.log('Səhvə yol açan nümunə...');
// console.log(temp); // Səhv: Cannot access 'temp' before initialization
let temp = 25;
console.log('Dəyər:', temp);
// Output:
// Səhvə yol açan nümunə...
// Dəyər: 25

